import json

# Get the data using locals() since variable name has special characters
var_name = 'var_functions.query_db:20'
assignment_data = locals().get(var_name, [])

# Process the data
cases_handled = {}
transfer_counts = {}

for record in assignment_data:
    new_agent = record['newvalue__c']
    old_agent = record['oldvalue__c']

    # Track cases handled
    if new_agent:
        cases_handled[new_agent] = cases_handled.get(new_agent, 0) + 1

    # Track transfers when oldvalue is not None
    if old_agent and old_agent != 'None':
        transfer_counts[old_agent] = transfer_counts.get(old_agent, 0) + 1

# Find agents with > 0 handled cases
eligible = []
for agent, handled in cases_handled.items():
    if handled > 0:
        transfers = transfer_counts.get(agent, 0)
        eligible.append((agent, transfers))

# Get agent with minimum transfers
if eligible:
    eligible.sort(key=lambda x: x[1])
    result = eligible[0][0]
else:
    result = None

print('__RESULT__:')
print(json.dumps(result))

